#!/usr/bin/env python3
"""scan-open-ports — TCP port scanner with concurrent scanning.

Usage:
  scan-open-ports <host>
  scan-open-ports <host> --ports=common
  scan-open-ports <host> --ports=all
  scan-open-ports <host> --ports=22,80,443
  scan-open-ports <host> --ports=1-1000
  scan-open-ports <host> --timeout=2 --workers=50

Options:
  --ports=PORTS   Port specification: comma-separated list, range (1-1000),
                  'common' (top 20), or 'all' (1-65535). Default: common.
  --timeout=N     Connection timeout in seconds. Default: 2.
  --workers=N     Number of concurrent workers. Default: 50.

Zero-dependency (stdlib only).
"""
