def parse_ports(port_str):
    """Parse a port specification string into a sorted list of port numbers."""
    if port_str == 'common':
        return list(COMMON_PORTS)
    if port_str == 'all':
        return list(range(1, 65536))

    ports = []
    parts = port_str.split(',')

    for part in parts:
        part = part.strip()
        if '-' in part:
            try:
                start, end = part.split('-', 1)
                start, end = int(start.strip()), int(end.strip())
                if start < 1:
                    start = 1
                if end > 65535:
                    end = 65535
                if start > end:
                    print(f"Error: invalid range {part}", file=sys.stderr)
                    sys.exit(1)
                ports.extend(range(start, end + 1))
            except ValueError:
                print(f"Error: invalid port range: {part}", file=sys.stderr)
                sys.exit(1)
        else:
            try:
                port = int(part)
                if port < 1 or port > 65535:
                    print(f"Error: port out of range (1-65535): {port}", file=sys.stderr)
                    sys.exit(1)
                ports.append(port)
            except ValueError:
                print(f"Error: invalid port: {part}", file=sys.stderr)
                sys.exit(1)

    return sorted(set(ports))


def get_service(port):
    """Return the known service name for a port, or 'unknown'."""
    return KNOWN_SERVICES.get(port, 'unknown')


def scan_port(host, port, timeout):
    """Attempt a TCP connection to host:port. Returns (port, state, service)."""
    sock = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
    sock.settimeout(timeout)
    try:
        result = sock.connect_ex((host, port))
        if result == 0:
            state = 'open'
        else:
            state = 'closed'
        sock.close()
    except socket.gaierror:
        return (port, 'error', 'hostname resolution failed')
    except OSError as e:
        state = f'error ({e})'
    except Exception:
        state = 'error'
    finally:
        try:
            sock.close()
        except Exception:
            pass

    if state == 'open':
        service = get_service(port)
        return (port, state, service)
    return (port, state, '')


def format_results(results, host, elapsed):
    """Display scan results as a formatted table."""
    open_ports = [r for r in results if r[1] == 'open']
    closed_count = sum(1 for r in results if r[1] == 'closed')
    error_count = sum(1 for r in results if r[1] != 'open' and r[1] != 'closed')

    if not open_ports:
        print(f"No open ports found on {host}")
        total = len(results)
        print(f"Scanned {total} port(s) in {elapsed:.2f}s ({closed_count} closed"
              f"{', ' + str(error_count) + ' errors' if error_count else ''})")
        return

    # Header
    print(f"\n{'PORT':<8} {'STATE':<8} {'SERVICE':<20}")
    print(f"{'----':<8} {'-----':<8} {'-------':<20}")

    for port, state, service in open_ports:
        print(f"{port:<8} {state:<8} {service:<20}")

    total = len(results)
    print(f"\nScanned {total} port(s) on {host} in {elapsed:.2f}s"
          f" — {len(open_ports)} open"
          f"{', ' + str(closed_count) + ' closed' if closed_count else ''}"
          f"{', ' + str(error_count) + ' errors' if error_count else ''}")


def main():
    args = sys.argv[1:]

    if not args or args[0] in ('-h', '--help'):
        print(__doc__)
        return

    host = None
    port_spec = 'common'
    timeout = 2.0
    workers = 50

    i = 0
    while i < len(args):
        arg = args[i]
        if arg.startswith('--ports='):
            port_spec = arg.split('=', 1)[1]
        elif arg.startswith('--timeout='):
            try:
                timeout = float(arg.split('=', 1)[1])
                if timeout <= 0:
                    raise ValueError
            except ValueError:
                print(f"Error: invalid timeout value", file=sys.stderr)
                sys.exit(1)
        elif arg.startswith('--workers='):
            try:
                workers = int(arg.split('=', 1)[1])
                if workers < 1:
                    raise ValueError
            except ValueError:
                print(f"Error: invalid workers count", file=sys.stderr)
                sys.exit(1)
        elif not arg.startswith('--'):
            if host is None:
                host = arg
            else:
                print(f"Error: unexpected argument: {arg}", file=sys.stderr)
                print(__doc__)
                sys.exit(1)
        else:
            print(f"Error: unknown flag: {arg}", file=sys.stderr)
            sys.exit(1)
        i += 1

    if host is None:
        print("Error: no host specified", file=sys.stderr)
        print(__doc__)
        sys.exit(1)

    # Validate host format
    if not host.replace('.', '').replace(':', '').replace('-', '').isalnum():
        print(f"Error: invalid host: {host}", file=sys.stderr)
        sys.exit(1)

    ports = parse_ports(port_spec)

    if not ports:
        print("Error: no ports to scan", file=sys.stderr)
        sys.exit(1)

    print(f"Scanning {host} ({len(ports)} port(s), timeout={timeout}s, workers={workers})...")
    sys.stdout.flush()

    start_time = time.time()
    results = []

    with concurrent.futures.ThreadPoolExecutor(max_workers=workers) as executor:
        future_to_port = {
            executor.submit(scan_port, host, port, timeout): port
            for port in ports
        }
        for future in concurrent.futures.as_completed(future_to_port):
            try:
                result = future.result()
                results.append(result)
            except Exception as e:
                port = future_to_port[future]
                results.append((port, 'error', str(e)))

    elapsed = time.time() - start_time

    # Sort results by port number (closed ports at end)
    results.sort(key=lambda r: (0 if r[1] == 'open' else 1, r[0]))

    format_results(results, host, elapsed)


if __name__ == '__main__':
    main()
